  "inlineSchema": "// Lexi AI — data model (maps to the screens in the Expo app)\n// learn more: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider      = \"prisma-client-js\"\n  binaryTargets = [\"native\", \"windows\"]\n  output        = \"../src/generated/prisma/client\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n/// A learner profile (the child using the app)\nmodel Child {\n  id      String  @id @default(cuid())\n  clerkId String? @unique // the Clerk user this learner belongs to\n  email   String?\n  name    String\n  avatar  String  @default(\"🦊\")\n  level   Int     @default(1)\n  title   String  @default(\"Унших аялагч\")\n  stars   Int     @default(0)\n  streak  Int     @default(0)\n  coins   Int     @default(0)\n  exp     Int     @default(0) // туршлагын оноо — цугларах тусам түвшин ахина\n\n  // Lexi-AI дислекси урьдчилсан шалгалт (шинэ хэрэглэгч анх орж ирэхэд өгнө)\n  dyslexiaTestDone   Boolean   @default(false)\n  dyslexiaScore      Int? // зөв хариултын тоо (0..6)\n  dyslexiaRisk       String? // 'low' | 'medium' | 'high'\n  dyslexiaTestedAt   DateTime?\n  // Хамгийн сүүлийн шалгалтаар илэрсэн сул ур чадварууд (хичээлийг тааруулахад)\n  dyslexiaWeakSkills String[]  @default([])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  badges          Badge[]\n  readingSessions ReadingSession[]\n  gameResults     GameResult[]\n  dyslexiaTests   DyslexiaTest[]\n}\n\n/// Дислекси шалгалтын нэг оролдлогын дэлгэрэнгүй үр дүн\nmodel DyslexiaTest {\n  id         String   @id @default(cuid())\n  score      Int // зөв хариултын тоо (0..6)\n  risk       String // 'low' | 'medium' | 'high'\n  answers    Json // [{ type, correct }] — даалгавар бүрийн хариу\n  weakSkills String[] // буруу хариулсан даалгаврын төрлүүд\n  createdAt  DateTime @default(now())\n\n  child   Child  @relation(fields: [childId], references: [id], onDelete: Cascade)\n  childId String\n}\n\n/// An earned (or locked) achievement badge\nmodel Badge {\n  id       String  @id @default(cuid())\n  key      String\n  label    String\n  emoji    String\n  unlocked Boolean @default(false)\n\n  child   Child  @relation(fields: [childId], references: [id], onDelete: Cascade)\n  childId String\n\n  @@unique([childId, key])\n}\n\n/// One reading practice session — drives the Parent dashboard stats\nmodel ReadingSession {\n  id          String   @id @default(cuid())\n  accuracy    Float    @default(0) // 0..100\n  durationMin Int      @default(0)\n  wordsRead   Int      @default(0)\n  lessonId    String?\n  createdAt   DateTime @default(now())\n\n  child   Child  @relation(fields: [childId], references: [id], onDelete: Cascade)\n  childId String\n}\n\n/// A reading lesson (the Reading screen)\nmodel Lesson {\n  id        String   @id @default(cuid())\n  order     Int      @unique\n  letter    String\n  title     String\n  emoji     String   @default(\"📖\")\n  createdAt DateTime @default(now())\n}\n\n/// A story in the Story World screen\nmodel Story {\n  id       String  @id @default(cuid())\n  title    String\n  emoji    String\n  level    String\n  category String\n  hasAudio Boolean @default(true)\n  minutes  Int     @default(5)\n}\n\n/// A learning game tile\nmodel Game {\n  id       String @id @default(cuid())\n  title    String\n  subtitle String\n  emoji    String\n}\n\n/// Result of playing a game\nmodel GameResult {\n  id        String   @id @default(cuid())\n  gameTitle String\n  score     Int      @default(0)\n  createdAt DateTime @default(now())\n\n  child   Child  @relation(fields: [childId], references: [id], onDelete: Cascade)\n  childId String\n}\n",
